// // This is a synchronous D flip-flop with a configurable data width, where the output Q stores the value of input D on the falling edge of the clock signal clk.
module top_module(clk,D,Q);parameter n=1;
  input clk;
  input [n-1:0] D;
  output [n-1:0] Q;
  reg [n-1:0] Q;
  always @(posedge clk)
    Q <= D;endmodule
